1	package mage.cards.e;
2	
3	import mage.MageObject;
4	import mage.abilities.Ability;
5	import mage.abilities.triggers.BeginningOfUpkeepTriggeredAbility;
6	import mage.abilities.common.EntersBattlefieldAbility;
7	import mage.abilities.effects.OneShotEffect;
8	import mage.abilities.effects.common.CopyPermanentEffect;
9	import mage.cards.Card;
10	import mage.cards.CardImpl;
11	import mage.cards.CardSetInfo;
12	import mage.constants.CardType;
13	import mage.constants.Outcome;
14	import mage.constants.Zone;
15	import mage.filter.FilterPermanent;
16	import mage.filter.common.FilterControlledEnchantmentPermanent;
17	import mage.game.Game;
18	import mage.game.permanent.Permanent;
19	import mage.players.Player;
20	import mage.util.functions.CopyApplier;
21	
22	import java.util.UUID;
23	
24	/**
25	 * @author TheElk801
26	 */
27	public final class EstridsInvocation extends CardImpl {
28	
29	    private static final FilterPermanent filter = new FilterControlledEnchantmentPermanent();
30	
31	    public EstridsInvocation(UUID ownerId, CardSetInfo setInfo) {
32	        super(ownerId, setInfo, new CardType[]{CardType.ENCHANTMENT}, "{2}{U}");
33	
34	        // You may have Estrid's Invocation enter the battlefield as a copy of any enchantment you control, except it gains "At the beginning of your upkeep, you may exile this enchantment. If you do, return it to the battlefield under its owner's control."
35	        this.addAbility(new EntersBattlefieldAbility(new CopyPermanentEffect(
36	                filter, new EstridsInvocationCopyApplier()
37	        ).setText("as a copy of an enchantment you control, except it gains "
38	                + "\"At the beginning of your upkeep, "
39	                + "you may exile this enchantment. "
40	                + "If you do, return it to the battlefield "
41	                + "under its owner's control.\""), true
42	        ));
43	    }
44	
45	    private EstridsInvocation(final EstridsInvocation card) {
46	        super(card);
47	    }
48	
49	    @Override
50	    public EstridsInvocation copy() {
51	        return new EstridsInvocation(this);
52	    }
53	}
54	
55	class EstridsInvocationCopyApplier extends CopyApplier {
56	
57	    @Override
58	    public boolean apply(Game game, MageObject blueprint, Ability source, UUID copyToObjectId) {
59	        // At the beginning of your upkeep, you may exile this enchantment. If you do, return it to the battlefield under its owner's control.
60	        blueprint.getAbilities().add(new BeginningOfUpkeepTriggeredAbility(
61	                new EstridsInvocationEffect(), true
62	        ));
63	        return true;
64	    }
65	}
66	
67	class EstridsInvocationEffect extends OneShotEffect {
68	
69	    EstridsInvocationEffect() {
70	        super(Outcome.Neutral);
71	        this.staticText = "exile this enchantment. If you do, return it to the battlefield under its owner's control";
72	    }
73	
74	    private EstridsInvocationEffect(final EstridsInvocationEffect effect) {
75	        super(effect);
76	    }
77	
78	    @Override
79	    public EstridsInvocationEffect copy() {
80	        return new EstridsInvocationEffect(this);
81	    }
82	
83	    @Override
84	    public boolean apply(Game game, Ability source) {
85	        Player player = game.getPlayer(source.getControllerId());
86	        Permanent permanent = source.getSourcePermanentIfItStillExists(game);
87	        if (permanent == null || player == null) {
88	            return false;
89	        }
90	        Card card = permanent.getMainCard();
91	        player.moveCards(permanent, Zone.EXILED, source, game);
92	        player.moveCards(card, Zone.BATTLEFIELD, source, game, false, false, true, null);
93	        return true;
94	    }
95	}
