2082	    public Permanent copyPermanent(Permanent copyFromPermanent, UUID copyToPermanentId, Ability source, CopyApplier applier) {
2083	        return copyPermanent(Duration.Custom, copyFromPermanent, copyToPermanentId, source, applier);
2084	    }
