2086	    @Override
2087	    public Permanent copyPermanent(Duration duration, Permanent copyFromPermanent, UUID copyToPermanentId, Ability source, CopyApplier applier) {
2088	        Permanent newBluePrint = null;
2089	        // handle copies of copies
2090	        for (Effect effect : getState().getContinuousEffects().getLayeredEffects(this)) {
2091	            if (effect instanceof CopyEffect) {
2092	                CopyEffect copyEffect = (CopyEffect) effect;
2093	                // there is another copy effect that our targetPermanent copies stats from
2094	                if (copyEffect.getSourceId().equals(copyFromPermanent.getId())) {
2095	                    MageObject oldBluePrint = ((CopyEffect) effect).getTarget();
2096	                    if (oldBluePrint instanceof Permanent) {
2097	                        // copy it and apply the applier if any
2098	                        newBluePrint = ((Permanent) oldBluePrint).copy();
2099	                    }
2100	                }
2101	            }
2102	        }
2103	
2104	        // if it was no copy of copy take the target itself
2105	        if (newBluePrint == null) {
2106	            newBluePrint = copyFromPermanent.copy();
2107	
2108	            // reset to original characteristics
2109	            newBluePrint.resetLockedStatus(); // reset locked status so room characteristics are correct
2110	            newBluePrint.reset(this);
2111	
2112	            // workaround to find real copyable characteristics of transformed/facedown/etc permanents
2113	
2114	            BecomesFaceDownCreatureEffect.FaceDownType faceDownType = BecomesFaceDownCreatureEffect.findFaceDownType(this, copyFromPermanent);
2115	            if (faceDownType != null) {
2116	                BecomesFaceDownCreatureEffect.makeFaceDownObject(this, null, newBluePrint, faceDownType, null);
2117	            }
2118	            newBluePrint.assignNewId();
2119	            if (copyFromPermanent.isPrototyped()) {
2120	                Abilities<Ability> abilities = copyFromPermanent.getAbilities();
2121	                for (Ability ability : abilities) {
2122	                    if (ability instanceof PrototypeAbility) {
2123	                        ((PrototypeAbility) ability).prototypePermanent(newBluePrint, this);
2124	                    }
2125	                }
2126	            }
2127	        }
2128	        if (applier != null) {
2129	            applier.apply(this, newBluePrint, source, copyToPermanentId);
2130	        }
2131	
2132	        // save original copy link (handle copy of copies too)
2133	        newBluePrint.setCopy(true, (copyFromPermanent.getCopyFrom() != null ? copyFromPermanent.getCopyFrom() : copyFromPermanent));
2134	
2135	        CopyEffect newCopyEffect = new CopyEffect(duration, newBluePrint, copyToPermanentId);
2136	        newCopyEffect.setApplier(applier);
2137	        Ability newAbility = source.copy();
2138	        newCopyEffect.init(newAbility, this);
2139	
2140	        // If there are already copy effects with duration = Custom to the same object, remove the existing effects because they no longer have any effect
2141	        if (duration == Duration.Custom) {
2142	            for (Effect effect : getState().getContinuousEffects().getLayeredEffects(this)) {
2143	                if (effect instanceof CopyEffect) {
2144	                    CopyEffect copyEffect = (CopyEffect) effect;
2145	                    // there is another copy effect that copies to the same permanent
2146	                    if (copyEffect.getSourceId().equals(copyToPermanentId) && copyEffect.getDuration() == Duration.Custom) {
2147	                        copyEffect.discard();
2148	                    }
2149	                }
2150	            }
2151	        }
2152	        state.addEffect(newCopyEffect, newAbility);
2153	        return newBluePrint;
2154	    }
