tool_use_result.originalFile:
package org.mage.test.cards.single.c18;

import mage.constants.PhaseStep;
import mage.constants.Zone;
import org.junit.Test;
import org.mage.test.serverside.base.CardTestPlayerBase;

public class EstridsInvocationTest extends CardTestPlayerBase {

    @Test
    public void testCanFlickerItselfOnConsecutiveUpkeeps() {
        addCard(Zone.HAND, playerA, "Estrid's Invocation");
        addCard(Zone.BATTLEFIELD, playerA, "Island", 3);
        addCard(Zone.BATTLEFIELD, playerA, "Crusade");
        addCard(Zone.BATTLEFIELD, playerA, "Savannah Lions");

        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Estrid's Invocation");
        setChoice(playerA, true); // copy an enchantment
        setChoice(playerA, "Crusade");

        checkPermanentCount("after cast", 1, PhaseStep.POSTCOMBAT_MAIN, playerA, "Crusade", 2);
        checkPT("after cast", 1, PhaseStep.POSTCOMBAT_MAIN, playerA, "Savannah Lions", 4, 3);

        setChoice(playerA, true); // first upkeep: exile and return it
        setChoice(playerA, true); // copy an enchantment again
        setChoice(playerA, "Crusade");
        checkPermanentCount("after first upkeep", 3, PhaseStep.PRECOMBAT_MAIN, playerA, "Crusade", 2);
        checkPT("after first upkeep", 3, PhaseStep.PRECOMBAT_MAIN, playerA, "Savannah Lions", 4, 3);

        setChoice(playerA, true); // second upkeep: exile and return it again
        setChoice(playerA, true); // copy an enchantment again
        setChoice(playerA, "Crusade");
        checkPermanentCount("after second upkeep", 5, PhaseStep.PRECOMBAT_MAIN, playerA, "Crusade", 2);
        checkPT("after second upkeep", 5, PhaseStep.PRECOMBAT_MAIN, playerA, "Savannah Lions", 4, 3);

        setStrictChooseMode(true);
        setStopAt(5, PhaseStep.PRECOMBAT_MAIN);
        execute();

        assertPermanentCount(playerA, "Crusade", 2);
        assertPowerToughness(playerA, "Savannah Lions", 4, 3);
    }
}

