220	    private void checkTrigger(TriggeredAbility ability, GameEvent event, Game game) {
221	        // for effects like when leaves battlefield or destroyed use ShortLKI to check if permanent was in the correct zone before (e.g. Oblivion Ring or Karmic Justice)
222	        if (this.enableIntegrityLogs) {
223	            logger.info("---");
224	            logger.info("checking trigger: " + ability);
225	            logger.info("playable state: " + game.inCheckPlayableState());
226	            logger.info(game);
227	            logger.info("battlefield:" + "\n" + game.getBattlefield().getAllPermanents().stream()
228	                    .map(p -> "- " + p.toString())
229	                    .collect(Collectors.joining("\n")) + "\n");
230	        }
231	        MageObject object = game.getObject(ability.getSourceId());
232	        if (ability.isInUseableZone(game, object, event)) {
233	            if (event == null || !game.getContinuousEffects().preventedByRuleModification(event, ability, game, false)) {
234	                if (object != null) {
235	                    boolean controllerSet = false; // TODO: wtf?!?!? Need rework whole "set" logic here
236	                    Set<UUID> eventTargets = CardUtil.getEventTargets(event);
237	                    if (ability.getZone() != Zone.COMMAND
238	                            && event != null
239	                            && !eventTargets.isEmpty()
240	                            && ability.isLeavesTheBattlefieldTrigger()
241	                            && game.getLKI().get(Zone.BATTLEFIELD) != null
242	                            && game.getLKI().get(Zone.BATTLEFIELD).containsKey(ability.getSourceId())) {
243	                        // need to check if object was face down for dies and destroy events because the ability triggers in the new zone, zone counter -1 is used
244	                        Permanent permanent = (Permanent) game.getLastKnownInformation(ability.getSourceId(), Zone.BATTLEFIELD, ability.getStackMomentSourceZCC() - 1);
245	                        if (permanent != null) {
246	                            if (permanent.isFaceDown(game)
247	                                    && !isGainedAbility(ability, permanent) // the face down creature got the ability from an effect => so it should work
248	                                    && !ability.getWorksFaceDown()) { // the ability is declared to work also face down
249	                                // Not all triggered abilities of face down creatures work if they are faced down
250	                                return;
251	                            }
252	                            controllerSet = true;
253	                            ability.setControllerId(permanent.getControllerId());
254	                        }
255	                    }
256	                    if (!controllerSet) {
257	                        if (object instanceof Permanent) {
258	                            ability.setControllerId(((Permanent) object).getControllerId());
259	                        } else if (object instanceof Spell) {
260	                            // needed so that cast triggered abilities have to correct controller (e.g. Ulamog, the Infinite Gyre).
261	                            ability.setControllerId(((Spell) object).getControllerId());
262	                        }
263	                    }
264	                }
265	
266	                if (ability.checkTrigger(event, game) && ability.checkTriggeredLimit(game) && !ability.checkUsedAlready(game)) {
267	                    NumberOfTriggersEvent numberOfTriggersEvent = new NumberOfTriggersEvent(ability, event);
268	                    // event == null - state based triggers like StateTriggeredAbility, must be ignored for number event
269	                    if (event == null || !game.replaceEvent(numberOfTriggersEvent, ability)) {
270	                        int limit = Integer.min(ability.getRemainingTriggersLimitEachGame(game), ability.getRemainingTriggersLimitEachTurn(game));
271	                        int numTriggers = Integer.min(limit, numberOfTriggersEvent.getAmount());
272	                        for (int i = 0; i < numTriggers; i++) {
273	                            if (this.enableIntegrityLogs) {
274	                                logger.info("trigger will be USED: " + ability);
275	                            }
276	                            ability.trigger(game, ability.getControllerId(), event);
277	                        }
278	                    }
279	                }
280	            }
281	        }
282	    }
